const $=s=>document.querySelector(s);const api=async(url,options={})=>{const r=await fetch(`/api${url}`,{headers:{'content-type':'application/json'},...options});if(!r.ok){const e=await r.json().catch(()=>({error:r.statusText}));throw new Error(e.error||r.statusText)}return r.status===204?null:r.json()};let agentCache=[];
const titles={dashboard:['Visão geral','Operação integrada do ambiente'],manager:['Gerente','Chat operacional com RAG e ferramentas MCP'],agents:['Agentes','Automação controlada por contas GLPI'],projetos:['Projetos','Codebases registradas para análise via OpenCode'],consumo:['Consumo','Tokens, custo estimado e uso de agentes'],settings:['Configurações','Integrações, modelos e credenciais'],runs:['Execuções','Auditoria dos trabalhos realizados']};
titles.reports=['Relatórios','Indicadores operacionais e produtividade da equipe'];
titles.ferramentas=['Ferramentas','Testes de qualidade: visual, segurança e carga'];
const mainEl=document.querySelector('main');let viewCache=[];
function navigate(page,replace){if(!page)page='dashboard';document.querySelectorAll('nav button').forEach(x=>x.classList.toggle('active',x.dataset.page===page));document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));if(page.startsWith('view-')){const v=viewCache.find(x=>'view-'+x.id===page);if(v){const sec=ensureViewSection(v);sec.classList.add('active');$('#title').textContent=v.label;$('#subtitle').textContent=v.url;const f=sec.querySelector('iframe');if(f.dataset.src&&f.getAttribute('src')!==f.dataset.src)f.src=f.dataset.src}else{navigate('dashboard');return}}else{const sec=document.getElementById(page);if(sec){sec.classList.add('active');$('#title').textContent=(titles[page]||[page])[0];$('#subtitle').textContent=(titles[page]||['',''])[1];loadPage(page)}}const url='/'+page;if(location.pathname!==url)(replace?history.replaceState:history.pushState)(null,'',url)}
document.querySelector('nav').addEventListener('click',e=>{const b=e.target.closest('button[data-page]');if(b)navigate(b.dataset.page)});
function routeFromPath(){const p=location.pathname.replace(/\/$/,'');navigate(p.slice(1)||'dashboard',true)}
window.addEventListener('popstate',()=>routeFromPath());
function ensureViewSection(v){let sec=document.getElementById('view-'+v.id);if(!sec){sec=document.createElement('section');sec.className='page';sec.id='view-'+v.id;sec.innerHTML=`<div class="toolbar"><p class="webview-url"></p><a class="ghost btn-link" target="_blank" rel="noopener">Abrir em nova aba ↗</a></div><div class="webview-wrap"><iframe class="webview" referrerpolicy="no-referrer"></iframe><div class="webview-hint">Carregado por proxy embutido. Se algo não funcionar (sites muito dinâmicos), use “Abrir em nova aba”.</div></div>`;mainEl.appendChild(sec);}
// O iframe carrega pelo proxy de embed (mesma origem, sem bloqueio de X-Frame-Options)
sec.querySelector('iframe').dataset.src='/embed/'+v.id+'/';sec.querySelector('.webview-url').textContent=v.url;sec.querySelector('.btn-link').href=v.url;return sec}
function renderSidebarViews(){$('#custom-nav').innerHTML=viewCache.filter(v=>v.enabled!==false).map(v=>`<button data-page="view-${v.id}"><span class="nav-ico">${esc(v.icon||(v.label||'•')[0])}</span>${esc(v.label)}</button>`).join('')}
async function loadViews(){try{viewCache=await api('/views')}catch{viewCache=[]}renderSidebarViews()}
function renderViewsList(){const box=$('#views-list');if(!box)return;box.innerHTML=viewCache.length?viewCache.map(v=>`<div class="view-row"><span class="nav-ico">${esc(v.icon||(v.label||'•')[0])}</span><div class="view-info"><strong>${esc(v.label)}</strong><small>${esc(v.url)}</small></div><div class="view-row-actions"><button class="ghost" onclick="editView('${v.id}')">Editar</button><button class="ghost danger" onclick="deleteView('${v.id}')">Excluir</button></div></div>`).join(''):'<p class="meta">Nenhuma tela personalizada ainda. Adicione o Grafana, GLPI ou Trello acima.</p>'}
function resetViewForm(){$('#view-id').value='';$('#view-icon').value='';$('#view-label').value='';$('#view-url').value=''}
function editView(id){const v=viewCache.find(x=>x.id===id);if(!v)return;$('#view-id').value=v.id;$('#view-icon').value=v.icon||'';$('#view-label').value=v.label;$('#view-url').value=v.url;$('#view-label').focus()}
async function deleteView(id){if(!confirm('Excluir esta tela?'))return;await api('/views/'+id,{method:'DELETE'});const sec=document.getElementById('view-'+id);if(sec)sec.remove();await loadViews();renderViewsList();if(location.pathname.includes('view-'+id))navigate('settings')}
const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const GLPI_STATUS={1:'Novo',2:'Em atendimento',3:'Planejado',4:'Pendente'};
function elapsedSince(value){if(!value)return 'data não informada';const ms=Date.now()-new Date(value).getTime();if(ms<0)return 'agora';const days=Math.floor(ms/86400000),hours=Math.floor(ms%86400000/3600000),minutes=Math.floor(ms%3600000/60000);if(days)return `${days}d ${hours}h aberto`;if(hours)return `${hours}h ${minutes}min aberto`;return `${Math.max(1,minutes)}min aberto`}
function renderTicketQueue(items,showTech=false,glpiWebUrl=''){return items.length?items.map(t=>{const content=`<div class="ticket-main"><div class="ticket-heading"><strong>#${t.id} · ${esc(t.name)}</strong><span class="glpi-status s${t.status}">${esc(GLPI_STATUS[t.status]||t.status)}</span></div><div class="ticket-meta"><span>${elapsedSince(t.createdAt)}</span>${showTech?`<span>Técnico: ${esc(t.technicians?.join(', ')||'Não atribuído')}</span>`:''}<span class="ticket-open-hint">Abrir no GLPI ↗</span></div></div>`;return glpiWebUrl?`<a class="ticket-row ticket-link" href="${esc(glpiWebUrl)}/front/ticket.form.php?id=${t.id}" target="_blank" rel="noopener">${content}</a>`:`<article class="ticket-row">${content}</article>`}).join(''):'<p class="meta empty-queue">Nenhum chamado nesta fila.</p>'}
async function loadDashboard(){const d=await api('/dashboard');const q=d.ticketQueues||{open:[],inProgress:[],pending:[]};const runCounts=Object.fromEntries(d.runs.map(x=>[x.status,x._count]));const rate=d.exchangeRate?.usdBrl;const rateInfo=rate?`<span class="rate-info">● cotação R$ ${rate.toFixed(2)}</span>`:'';$('#metrics').innerHTML=[['Chamados ativos',`${q.open.length+q.inProgress.length+q.pending.length}`],['Custo estimado no mês',`${fmtBrl(d.costs?.monthBrl)} <small class="usd-sub">${fmtUsd(d.costs?.monthUsd)}</small>`],['Custo estimado total',`${fmtBrl(d.costs?.totalBrl)} <small class="usd-sub">${fmtUsd(d.costs?.totalUsd)}</small>`],['Agentes',`${d.agentCount}`],['Execuções OK',`${runCounts.SUCCEEDED||0} ${rateInfo}`]].map(x=>`<div class="metric"><span>${x[0]}</span><strong>${x[1]}</strong></div>`).join('');$('#open-count').textContent=q.open.length;$('#progress-count').textContent=q.inProgress.length;$('#pending-count').textContent=q.pending.length;$('#open-tickets').innerHTML=renderTicketQueue(q.open,false,d.glpiWebUrl);$('#progress-tickets').innerHTML=renderTicketQueue(q.inProgress,true,d.glpiWebUrl);$('#pending-tickets').innerHTML=renderTicketQueue(q.pending,true,d.glpiWebUrl);$('#recent-runs').innerHTML=renderRuns(d.recentRuns)}
function renderRuns(runs){return runs.length?runs.map(r=>`<button class="run-row run-link" onclick="openRun('${r.id}')"><div><strong>${esc(r.agent?.name||'Agente')}</strong><div class="meta">${esc(r.kind)} · ${new Date(r.createdAt).toLocaleString()}</div></div><div><span class="status ${r.status}">${r.status}</span>${r.durationMs?` <small>${Math.round(r.durationMs/1000)}s</small>`:''}<span class="run-actions">${r.status==='RUNNING'||r.status==='QUEUED'?`<button class="ghost danger cancel-btn" onclick="event.stopPropagation();cancelRun('${r.id}')">Cancelar</button>`:''}${['FAILED','TIMED_OUT','CANCELLED'].includes(r.status)?`<button class="ghost restart-btn" id="restart-${r.id}" onclick="event.stopPropagation();restartRun('${r.id}')">🔄 Reiniciar</button>`:''}</span></div></button>`).join(''):'<p class="meta">Nenhuma execução registrada.</p>'}
let runPoll=null,currentRunId=null;
async function refreshRun(){if(!currentRunId)return;try{const r=await api('/runs/'+currentRunId);const running=r.status==='RUNNING'||r.status==='QUEUED';const failed=['FAILED','TIMED_OUT','CANCELLED'].includes(r.status);$('#run-title').textContent=`${r.agent?.name||'Agente'} · ${r.kind}`;$('#run-subtitle').textContent=r.glpiTicketId?`Chamado GLPI #${r.glpiTicketId}`:`Execução ${r.id}`;$('#run-detail-meta').innerHTML=`<span class="status ${r.status}">${r.status}</span><span>${r.startedAt?new Date(r.startedAt).toLocaleString():'Aguardando início'}</span><span>${r.durationMs?Math.round(r.durationMs/1000)+'s':'Em andamento'}</span>${r.exitCode!==null?`<span>Exit code: ${r.exitCode}</span>`:''}${running?`<button class="ghost danger" id="run-cancel-btn" onclick="cancelRun('${r.id}')">Cancelar execução</button>`:''}${failed?`<button class="ghost" id="run-restart-btn" onclick="restartRun('${r.id}')">🔄 Reiniciar execução</button>`:''}`;const text=[r.output?`STDOUT\n${r.output}`:'',r.error?`STDERR\n${r.error}`:''].filter(Boolean).join('\n\n');const consoleEl=$('#run-console'),atBottom=consoleEl.scrollHeight-consoleEl.scrollTop-consoleEl.clientHeight<60;consoleEl.textContent=text||'Aguardando saída do CLI...';if(atBottom)consoleEl.scrollTop=consoleEl.scrollHeight;if(!running){clearInterval(runPoll);runPoll=null}}catch(e){$('#run-console').textContent=e.message}}
function openRun(id){currentRunId=id;$('#run-console').textContent='Carregando console...';$('#run-dialog').showModal();refreshRun();clearInterval(runPoll);runPoll=setInterval(refreshRun,1000)}
function closeRun(){clearInterval(runPoll);runPoll=null;currentRunId=null;$('#run-dialog').close()}
async function cancelRun(id){if(!confirm('Cancelar esta execução?'))return;try{await api('/runs/'+id+'/cancel',{method:'POST',body:'{}'});if(currentRunId===id){refreshRun();$('#run-cancel-btn')?.remove()}if(window.loadRuns)loadRuns();if(window.loadDashboard)loadDashboard()}catch(e){alert(e.message)}}
async function restartRun(id){if(!confirm('Reiniciar esta execução? O chamado voltará para Em andamento.'))return;const btn=document.getElementById('restart-'+id)||document.getElementById('run-restart-btn');if(btn){btn.disabled=true;btn.innerHTML='⏳ Reiniciando...'}try{const r=await api('/runs/'+id+'/restart',{method:'POST',body:'{}'});if(window.loadRuns)loadRuns();if(window.loadDashboard)loadDashboard();if(currentRunId)openRun(r.newRun.id)}catch(e){if(btn){btn.disabled=false;btn.innerHTML='🔄 Reiniciar'}alert(e.message)}}
async function loadAgents(){agentCache=await api('/agents');$('#agent-list').innerHTML=agentCache.map(a=>`<article class="agent-card"><div class="top"><div><h3>${esc(a.name)}</h3><small>${esc(a.provider)} · ${esc(a.mode)}</small></div><span class="badge">${a.enabled?'ATIVO':'PAUSADO'}</span></div><p>${esc(a.description||'Sem descrição')}</p><div class="path" title="${esc(a.projectPath)}">${esc(a.projectPath)}</div><div class="actions"><button onclick="editAgent('${a.id}')">Editar</button><button class="ghost" onclick="testAgent('${a.id}')">Testar agente</button><button class="ghost" onclick="createGlpi('${a.id}')">${a.glpiUserId?'GLPI #'+a.glpiUserId:'Criar conta GLPI'}</button><button class="ghost danger" onclick="deleteAgent('${a.id}')">Excluir</button></div></article>`).join('')}
function openAgent(a={}){$('#agent-id').value=a.id||'';$('#agent-name').value=a.name||'';$('#agent-description').value=a.description||'';$('#agent-provider').value=a.provider||'OPENCODE';$('#agent-mode').value=a.mode||'ANALYZE';$('#agent-path').value=a.projectPath||'';$('#agent-model').value=a.model||'';$('#agent-instructions').value=a.instructions||'';$('#agent-enabled').checked=a.enabled??true;$('#agent-result').classList.add('hidden');$('#agent-dialog').showModal()}function editAgent(id){openAgent(agentCache.find(a=>a.id===id))}function closeAgent(){$('#agent-dialog').close()}
$('#agent-form').onsubmit=async e=>{e.preventDefault();const id=$('#agent-id').value;const body={name:$('#agent-name').value,description:$('#agent-description').value,provider:$('#agent-provider').value,mode:$('#agent-mode').value,projectPath:$('#agent-path').value,instructions:$('#agent-instructions').value,model:$('#agent-model').value||null,enabled:$('#agent-enabled').checked};await api(id?`/agents/${id}`:'/agents',{method:id?'PUT':'POST',body:JSON.stringify(body)});closeAgent();loadAgents()};
async function pickFolder(b){b.disabled=true;b.textContent='Aguardando janela...';try{const r=await api('/system/pick-folder',{method:'POST',body:'{}'});if(r.path)$('#agent-path').value=r.path}catch(e){alert(e.message)}finally{b.disabled=false;b.textContent='Selecionar pasta'}}
async function testAgent(id){const a=agentCache.find(x=>x.id===id);openAgent(a);const box=$('#agent-result');box.classList.remove('hidden');box.textContent='Executando teste oneshot no Windows...';try{const r=await api(`/agents/${id}/test`,{method:'POST',body:'{}'});box.textContent=`${r.status}\n\n${r.output||r.error||'Sem saída'}`}catch(e){box.textContent=e.message}}
async function createGlpi(id){if(agentCache.find(a=>a.id===id)?.glpiUserId)return;try{const r=await api(`/agents/${id}/glpi-account`,{method:'POST',body:'{}'});alert(`Conta criada. Guarde agora:\nUsuário: ${r.username}\nSenha: ${r.password}`);loadAgents()}catch(e){alert(e.message)}}async function deleteAgent(id){if(confirm('Excluir este agente e seu histórico?')){await api(`/agents/${id}`,{method:'DELETE'});loadAgents()}}
async function loadSettings(){const [rows,modelData]=await Promise.all([api('/settings'),api('/manager/models').catch(()=>({models:[]}))]);$('#settings-form').innerHTML=rows.map(s=>{if(s.key==='MANAGER_MODEL'&&modelData.models.length){const options=modelData.models.map(m=>`<option value="${esc(m.id)}" title="${esc(m.description||'')}" ${m.id===s.value?'selected':''}>${esc(m.name)} · ${esc(m.id)}</option>`).join('');return `<label>${esc(s.key)}<small>modelos disponíveis para a GEMINI_API_KEY</small><select name="${esc(s.key)}">${options}</select></label>`}return `<label>${esc(s.key)}${s.secret?'<small>segredo criptografado</small>':''}<input name="${esc(s.key)}" value="${esc(s.value)}" ${s.secret?'type="password"':''}></label>`}).join('');await loadViews();renderViewsList()}
$('#view-form').onsubmit=async e=>{e.preventDefault();const id=$('#view-id').value;const body={label:$('#view-label').value.trim(),url:$('#view-url').value.trim(),icon:$('#view-icon').value.trim()||null};try{await api(id?'/views/'+id:'/views',{method:id?'PUT':'POST',body:JSON.stringify(body)});resetViewForm();await loadViews();renderViewsList()}catch(err){alert(err.message)}};$('#settings-form').onsubmit=async e=>{e.preventDefault();const body=Object.fromEntries(new FormData(e.target));await api('/settings',{method:'PUT',body:JSON.stringify(body)});alert('Configurações salvas. Reinicie o middleware ao trocar credenciais ou URLs de integrações.')};
let currentChannel='web';let msgSig='';let chanSig='';let channelCache=[];
function channelLabel(ch){if(ch==='web')return '🖥️ Painel (Web)';if(ch.startsWith('telegram:'))return '📨 Telegram · '+ch.slice(9);if(ch.startsWith('slack:'))return '💬 Slack · '+ch.slice(6);return ch}
function updateChatAccountButton(){const btn=$('#chat-account-btn'),current=channelCache.find(c=>c.channel===currentChannel);if(currentChannel==='web'){btn.classList.add('hidden');return}btn.classList.remove('hidden');btn.disabled=Boolean(current?.glpiUserId);btn.textContent=current?.glpiUserId?`${current.glpiUsername} · GLPI #${current.glpiUserId}`:'Configurar conta GLPI'}
function renderChannels(list){channelCache=list;const sig=JSON.stringify(list.map(c=>[c.channel,c.count,c.glpiUserId]));if(!list.some(c=>c.channel==='web'))list.unshift({channel:'web',count:0,lastAt:null,glpiUserId:null});if(sig!==chanSig){chanSig=sig;$('#channel-list').innerHTML=list.map(c=>`<button class="channel-item ${c.channel===currentChannel?'active':''}" onclick="selectChannel('${esc(c.channel)}')"><span class="ch-name">${esc(channelLabel(c.channel))}${c.glpiUserId?` <span class="glpi-chip">GLPI #${c.glpiUserId}</span>`:''}</span><span class="ch-meta">${c.lastAt?new Date(c.lastAt).toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'}):''}</span></button>`).join('')}updateChatAccountButton()}
async function loadChannels(){try{renderChannels(await api('/manager/channels'))}catch{}}
function selectChannel(ch){if(ch===currentChannel){updateChatAccountButton();return}currentChannel=ch;chanSig='';msgSig='';$('#chat-title').textContent=channelLabel(ch);$('#chat-sub').textContent=ch==='web'?'Conversa naturalmente e usa ferramentas quando necessário':'Você está respondendo nesta sessão — a resposta vai para a plataforma de origem';updateChatAccountButton();loadChannels();loadMessages()}
function syncChatAccountMode(){const create=$('#chat-account-mode').value==='create',username=$('#chat-account-username'),existing=$('#chat-account-existing');$('#chat-account-existing-field').classList.toggle('hidden',create);$('#chat-account-username-field').classList.toggle('hidden',!create);$('#chat-account-name-field').classList.toggle('hidden',!create);username.disabled=!create;username.required=create;existing.disabled=create;existing.required=!create;$('#chat-account-submit').textContent=create?'Criar conta':'Vincular conta';$('#chat-account-help').textContent=create?'A senha temporária será gerada e exibida uma única vez.':'Selecione uma conta ativa. A mesma pessoa pode ser vinculada ao Telegram e ao Slack.'}
async function loadAvailableGlpiUsers(){const select=$('#chat-account-existing');select.disabled=true;select.innerHTML='<option value="">Carregando contas...</option>';try{const users=await api('/manager/channels/available-glpi-users');select.innerHTML=users.length?'<option value="">Selecione uma conta</option>'+users.map(u=>`<option value="${esc(u.username)}">${esc(u.displayName)} · ${esc(u.username)} · #${u.id}</option>`).join(''):'<option value="">Nenhuma conta disponível</option>'}catch(err){select.innerHTML='<option value="">Erro ao carregar contas</option>';$('#chat-account-result').textContent=err.message;$('#chat-account-result').classList.remove('hidden')}finally{select.disabled=$('#chat-account-mode').value==='create'}}
function openChatAccount(){if(currentChannel==='web')return;$('#chat-account-channel').textContent=channelLabel(currentChannel);$('#chat-account-mode').value='link';$('#chat-account-existing').value='';$('#chat-account-username').value='';$('#chat-account-display-name').value='';$('#chat-account-result').classList.add('hidden');$('#chat-account-result').textContent='';syncChatAccountMode();$('#chat-account-dialog').showModal();loadAvailableGlpiUsers().then(()=>$('#chat-account-existing').focus())}
function closeChatAccount(){$('#chat-account-dialog').close()}
$('#chat-account-mode').onchange=syncChatAccountMode;
$('#chat-account-form').onsubmit=async e=>{e.preventDefault();const mode=$('#chat-account-mode').value,username=(mode==='create'?$('#chat-account-username').value:$('#chat-account-existing').value).trim(),displayName=$('#chat-account-display-name').value.trim(),button=$('#chat-account-submit'),result=$('#chat-account-result');button.disabled=true;result.classList.add('hidden');try{const r=await api('/manager/channels/account',{method:'POST',body:JSON.stringify({channel:currentChannel,mode,username,displayName:displayName||undefined})});if(mode==='create'){result.textContent=`Conta criada com sucesso.\nUsuário: ${r.username}\nSenha temporária: ${r.password}\n\nGuarde esta senha agora.`;result.classList.remove('hidden')}else{alert(`Conta ${r.username} vinculada ao chat com sucesso.`);closeChatAccount()}chanSig='';await loadChannels()}catch(err){result.textContent=err.message;result.classList.remove('hidden')}finally{button.disabled=false}};
function renderMessages(ms){const sig=ms.length+':'+(ms[ms.length-1]?.id||'')+':'+(ms[ms.length-1]?.content?.length||0);if(sig===msgSig)return;msgSig=sig;$('#messages').innerHTML=ms.map(m=>{let html='<div class="message '+m.role+'">'+esc(m.content);if(m.metadata?.attachments?.length){html+=m.metadata.attachments.map(a=>a.dataUrl?`<img class="chat-attach" src="${esc(a.dataUrl)}" alt="${esc(a.name||'')}" loading="lazy">`:`<span class="chip">📎 ${esc(a.name||'arquivo')}</span>`).join('')}html+=m.metadata?.source==='telegram'?'<small>via Telegram</small>':'';html+=m.metadata?.source==='slack'?'<small>via Slack</small>':'';html+=m.role==='assistant'&&m.metadata?.model?`<small>${esc(m.metadata.model)}</small>`:'';html+='</div>';return html}).join('');$('#messages').scrollTop=$('#messages').scrollHeight}
async function loadMessages(){msgSig='';const ms=await api('/manager/messages?channel='+encodeURIComponent(currentChannel)).catch(()=>[]);renderMessages(ms)}
async function loadManager(){await loadChannels();await loadMessages()}
async function pollMessages(){if(document.querySelector('.page.active')?.id!=='manager'||document.getElementById('thinking'))return;try{loadChannels();renderMessages(await api('/manager/messages?channel='+encodeURIComponent(currentChannel)))}catch{}}
setInterval(pollMessages,5000);
let pendingFiles=[];
const fileToB64=f=>new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(String(r.result).split(',')[1]);r.onerror=rej;r.readAsDataURL(f)});
function renderAttachPreview(){$('#attach-preview').innerHTML=pendingFiles.map((f,i)=>`<span class="chip">${esc(f.name)}<button type="button" onclick="removeFile(${i})">×</button></span>`).join('')}
function removeFile(i){pendingFiles.splice(i,1);renderAttachPreview()}
$('#chat-files').onchange=e=>{for(const f of e.target.files){if(f.size>25*1024*1024){alert(`"${f.name}" excede 25MB.`);continue}pendingFiles.push(f)}e.target.value='';renderAttachPreview()};
$('#chat-form').onsubmit=async e=>{e.preventDefault();const input=$('#chat-message'),message=input.value.trim();if(!message&&!pendingFiles.length)return;const files=pendingFiles.slice();pendingFiles=[];renderAttachPreview();input.value='';const tag=files.length?`<div class="att-tag">📎 ${files.map(f=>esc(f.name)).join(', ')}</div>`:'';$('#messages').insertAdjacentHTML('beforeend',`<div class="message user">${esc(message)||'<em>(anexo)</em>'}${tag}</div><div class="message assistant" id="thinking"><span class="typing">Gerente está pensando</span></div>`);$('#messages').scrollTop=$('#messages').scrollHeight;try{const attachments=await Promise.all(files.map(async f=>({mimeType:f.type||'application/octet-stream',data:await fileToB64(f),name:f.name})));const r=await api('/manager/chat',{method:'POST',body:JSON.stringify({message,attachments,channel:currentChannel})});$('#thinking').innerHTML=`${esc(r.answer)}<small>${esc(r.model)}</small>`;$('#thinking').removeAttribute('id')}catch(e){$('#thinking').textContent=e.message;$('#thinking').removeAttribute('id')}};function ask(t){$('#chat-message').value=t;$('#chat-form').requestSubmit()}async function reindex(){const r=await api('/knowledge/reindex',{method:'POST',body:'{}'});alert(`${r.indexed} chamados indexados no Qdrant.`)}
async function loadRuns(){$('#runs-table').innerHTML=renderRuns(await api('/runs'))}

// ---------- Markdown render ----------
function mdToHtml(md){if(!md)return '';const escaped=md.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');const lines=escaped.split('\n');let html='',inCode=false;for(let i=0;i<lines.length;i++){const l=lines[i];if(l.startsWith('```')){if(inCode){html+='</code></pre>';inCode=false}else{html+='<pre class="md-code"><code>';inCode=true}continue}if(inCode){html+=l+'\n';continue}if(!l.trim()){html+='<p class="md-p"></p>';continue}let processed=l;processed=processed.replace(/^### (.+)/,'<h4 class="md-h3">$1</h4>');processed=processed.replace(/^## (.+)/,'<h3 class="md-h2">$1</h3>');processed=processed.replace(/^# (.+)/,'<h2 class="md-h1">$1</h2>');if(processed!==l){html+=processed;continue}if(/^\s*[-*]\s/.test(l)){processed=processed.replace(/^\s*[-*]\s(.*)/,'<li class="md-li">$1</li>');html+=processed;continue}if(/^\s*\d+\.\s/.test(l)){processed=processed.replace(/^\s*\d+\.\s(.*)/,'<li class="md-li">$1</li>');html+=processed;continue}if(/^---+$/.test(l.trim())){html+='<hr class="md-hr">';continue}processed=processed.replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>');processed=processed.replace(/`([^`]+)`/g,'<code class="md-icode">$1</code>');processed=processed.replace(/\[([^\]]+)\]\(([^)]+)\)/g,'<a href="$2" target="_blank" rel="noopener">$1</a>');html+=`<p class="md-p">${processed}</p>`}if(inCode)html+='</code></pre>';return html.replace(/<p class="md-p"><\/p>/g,'<br>')}

// ---------- Projetos ----------
let projectCache=[];
function escScore(v){const n=Number(v);return isNaN(n)?'-':n.toFixed(1)}
function scoreBar(v,max=10){const n=Math.min(Math.max(Number(v)||0,0),max);const p=n/max*100;const color=n>=8?'var(--accent)':n>=5?'#f59e0b':'var(--danger)';return`<div class="score-bar"><div class="score-fill" style="width:${p}%;background:${color}"></div></div><span class="score-val">${n.toFixed(1)}</span>`}
const scoreLabels={architecture:'Arquitetura',security:'Segurança',performance:'Desempenho',technology:'Tecnologia',readability:'Legibilidade',monitoring:'Monitoramento',updateSupport:'Suporte a atualizações'};
async function loadProjetos(){projectCache=await api('/projects');$('#project-list').innerHTML=projectCache.map(p=>{
const scores=p.scores?Object.entries(p.scores).map(([k,v])=>`<div class="score-row"><span>${esc(scoreLabels[k]||k)}</span>${scoreBar(v)}</div>`).join(''):'<p class="meta">Ainda não analisado.</p>';
const statusClass=p.status.toLowerCase();
const overviewId='ov-'+p.id;
const overviewShort=p.overview?`<p class="ov-summary">${esc((p.overview.technology+' '+p.overview.features).slice(0,200))}...</p>`:'';
return `<article class="project-card" data-id="${esc(p.id)}"><div class="project-head"><div><h3>${esc(p.name)}</h3><small>${esc(p.projectPath)}</small></div><span class="badge ${statusClass}">${p.status}</span></div>${p.description?`<p>${esc(p.description)}</p>`:''}${p.scores?`<div class="project-scores">${scores}</div>`:''}${p.overview?`<div class="project-overview"><strong class="ov-toggle" onclick="toggleOv('${overviewId}')">📋 Visão geral <span class="ov-arrow">▸</span></strong>${overviewShort}<div id="${overviewId}" class="ov-full hidden"><p><strong>Tecnologia:</strong> ${esc(p.overview.technology)}</p><p><strong>Funcionalidades:</strong> ${esc(p.overview.features)}</p><p><strong>Arquitetura:</strong> ${esc(p.overview.architecture)}</p></div></div>`:''}${p.sshHost||p.sshAuthType!=='pm2'?`<div class="ssh-row"><span class="ssh-status">${p.sshConnected?`<span class="ssh-ok">SSH OK</span>`:`<span class="ssh-na">SSH não testado</span>`}</span><span class="ssh-info">${esc(p.sshHost||'PM2 (local)')}</span><button class="ghost" onclick="testProjectSsh('${p.id}')">Testar SSH</button></div>`:''}${p.error?`<div class="project-error">${esc(p.error)}</div>`:''}<div class="actions">${p.status==='ANALYZING'?'<span class="meta">Analisando...</span>':`<button onclick="analyzeProject('${p.id}')">Interpretar codebase</button>`}${p.documentation?`<button class="ghost" onclick="viewProjectDoc('${p.id}')">📄 Documentação</button>`:''}<button class="ghost" onclick="editProject('${p.id}')">Editar</button><button class="ghost danger" onclick="deleteProject('${p.id}')">Excluir</button></div></article>`
}).join('')||'<p class="meta" style="text-align:center;padding:40px">Nenhum projeto cadastrado. Clique em "Novo projeto" para adicionar uma codebase.</p>'}
function toggleOv(id){const el=document.getElementById(id);if(!el)return;const arrow=el.previousElementSibling?.querySelector('.ov-arrow');const show=el.classList.toggle('hidden');el.previousElementSibling?.classList.toggle('ov-open',!show);if(arrow)arrow.textContent=show?'▸':'▾'}
function openProject(p={}){$('#project-id').value=p.id||'';$('#project-name').value=p.name||'';$('#project-description').value=p.description||'';$('#project-path').value=p.projectPath||'';$('#project-ssh-host').value=p.sshHost||'';$('#project-ssh-port').value=p.sshPort||22;$('#project-ssh-user').value=p.sshUser||'';$('#project-ssh-auth-type').value=p.sshAuthType||'pm2';$('#project-ssh-key-path').value=p.sshKeyPath||'';$('#project-ssh-password').value='';sshAuthTypeChanged();$('#project-result').classList.add('hidden');$('#project-dialog').showModal()}
function sshAuthTypeChanged(){const t=$('#project-ssh-auth-type').value;$('#project-ssh-key-field').classList.toggle('hidden',t!=='key');$('#project-ssh-password-field').classList.toggle('hidden',t!=='password')}$('#project-ssh-auth-type').onchange=sshAuthTypeChanged;
function editProject(id){openProject(projectCache.find(p=>p.id===id))}
function closeProject(){$('#project-dialog').close()}
async function pickProjectFolder(b){b.disabled=true;b.textContent='Aguardando janela...';try{const r=await api('/system/pick-folder',{method:'POST',body:'{}'});if(r.path)$('#project-path').value=r.path}catch(e){alert(e.message)}finally{b.disabled=false;b.textContent='Selecionar pasta'}}
$('#project-form').onsubmit=async e=>{e.preventDefault();const id=$('#project-id').value;const body={name:$('#project-name').value,description:$('#project-description').value,projectPath:$('#project-path').value,sshHost:$('#project-ssh-host').value||null,sshPort:Number($('#project-ssh-port').value)||22,sshUser:$('#project-ssh-user').value||null,sshAuthType:$('#project-ssh-auth-type').value,sshKeyPath:$('#project-ssh-key-path').value||null,sshPassword:$('#project-ssh-password').value||null};await api(id?`/projects/${id}`:'/projects',{method:id?'PUT':'POST',body:JSON.stringify(body)});closeProject();loadProjetos()};
async function analyzeProject(id){if(!confirm('Iniciar análise completa da codebase via OpenCode? Isso pode levar alguns minutos.'))return;try{const r=await api(`/projects/${id}/analyze`,{method:'POST',body:'{}'});alert(r.message);loadProjetos()}catch(e){alert(e.message)}}
async function deleteProject(id){if(!confirm('Excluir este projeto e todos os dados da análise?'))return;await api(`/projects/${id}`,{method:'DELETE'});loadProjetos()}
function viewProjectDoc(id){const p=projectCache.find(x=>x.id===id);if(!p||!p.documentation)return;$('#doc-title').textContent=p.name;$('#doc-subtitle').textContent='Documentação gerada por OpenCode';$('#doc-content').innerHTML=mdToHtml(p.documentation);$('#project-doc-dialog').showModal()}
async function testProjectSsh(id){const p=projectCache.find(x=>x.id===id);if(!p)return;const btn=event?.target;if(btn){btn.disabled=true;btn.textContent='Testando...'}try{const r=await api(`/projects/${id}/ssh-test`,{method:'POST',body:'{}'});p.sshConnected=r.success;const row=document.querySelector(`.project-card[data-id="${id}"] .ssh-status`);if(row)row.innerHTML=r.success?`<span class="ssh-ok">SSH OK</span>`:`<span class="ssh-err">SSH falhou</span>`;if(!r.success)alert('Falha na conexão SSH: '+(r.error||'erro desconhecido'))}catch(e){alert(e.message)}finally{if(btn){btn.disabled=false;btn.textContent=r?.success?'Testar novamente':'Testar SSH'}}}
function closeProjectDoc(){$('#project-doc-dialog').close()}
// ---------- Consumo ----------
let usageRange='day';
const fmtInt=n=>(n||0).toLocaleString('pt-BR');
const fmtTokens=n=>{n=n||0;if(n>=1e9)return (n/1e9).toFixed(2)+'B';if(n>=1e6)return (n/1e6).toFixed(2)+'M';if(n>=1e3)return (n/1e3).toFixed(1)+'k';return String(n)};
const fmtUsd=n=>'$'+(n||0).toLocaleString('en-US',{minimumFractionDigits:n<1?4:2,maximumFractionDigits:n<1?4:2});
const fmtBrl=n=>'R$ '+(n||0).toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2});
const COLORS=['#6366f1','#22c55e','#f59e0b','#ef4444','#06b6d4','#a855f7','#ec4899','#84cc16'];
function bucketLabel(b){const p=b.split('-');if(p.length===2)return p[1]+'/'+p[0].slice(2);return p[2]+'/'+p[1]}
function setRange(r){usageRange=r;document.querySelectorAll('.range-btn').forEach(x=>x.classList.toggle('active',x.dataset.range===r));loadUsage()}
function lineChart(series,rate){if(!series.length)return '<p class="meta">Sem consumo registrado neste período.</p>';const W=720,H=220,pad=38;const max=Math.max(...series.map(s=>s.totalTokens),1);const n=series.length;const x=i=>pad+(n===1?0:i*(W-pad*2)/(n-1));const y=v=>H-pad-(v/max)*(H-pad*2);const pts=series.map((s,i)=>`${x(i)},${y(s.totalTokens)}`).join(' ');const area=`${pad},${H-pad} ${pts} ${x(n-1)},${H-pad}`;const dots=series.map((s,i)=>`<circle cx="${x(i)}" cy="${y(s.totalTokens)}" r="3" fill="#6366f1"><title>${esc(bucketLabel(s.bucket))}: ${fmtInt(s.totalTokens)} tokens · ${fmtBrl(s.costBrl)} · ${fmtUsd(s.costUsd)}</title></circle>`).join('');const labels=series.map((s,i)=>(n>10&&i%2)?'':`<text x="${x(i)}" y="${H-pad+16}" text-anchor="middle" class="ax">${esc(bucketLabel(s.bucket))}</text>`).join('');const yticks=[0,.5,1].map(f=>`<text x="${pad-6}" y="${y(max*f)+4}" text-anchor="end" class="ax">${fmtTokens(max*f)}</text><line x1="${pad}" y1="${y(max*f)}" x2="${W-pad}" y2="${y(max*f)}" class="grid"/>`).join('');return `<svg viewBox="0 0 ${W} ${H}" class="chart">${yticks}<polygon points="${area}" fill="url(#g)"/><polyline points="${pts}" fill="none" stroke="#6366f1" stroke-width="2"/>${dots}${labels}<defs><linearGradient id="g" x1="0" x2="0" y1="0" y2="1"><stop offset="0" stop-color="#6366f1" stop-opacity=".35"/><stop offset="1" stop-color="#6366f1" stop-opacity="0"/></linearGradient></defs></svg>`}
function barList(items,labelKey,valKey,fmt){if(!items.length)return '<p class="meta">Sem dados.</p>';const max=Math.max(...items.map(i=>i[valKey]),1);return '<div class="barlist">'+items.map((it,idx)=>`<div class="bar-row"><span class="bar-label" title="${esc(it[labelKey])}">${esc(it[labelKey])}</span><div class="bar-track"><div class="bar-fill" style="width:${Math.max(2,it[valKey]/max*100)}%;background:${COLORS[idx%COLORS.length]}"></div></div><span class="bar-val">${fmt(it[valKey])}</span></div>`).join('')+'</div>'}
async function loadUsage(){const d=await api('/usage?range='+usageRange);const rate=d.exchangeRate?.usdBrl;const rateInfo=rate?`<span class="rate-info">● cotação R$ ${rate.toFixed(2)}</span>`:'';$('#usage-metrics').innerHTML=[['Tokens totais',fmtInt(d.totals.totalTokens)],['Entrada',fmtInt(d.totals.promptTokens)],['Saída',fmtInt(d.totals.outputTokens)],['Custo estimado',`${fmtBrl(d.totals.costBrl)} <small class="usd-sub">${fmtUsd(d.totals.costUsd)}</small>`],['Chamadas de IA',`${fmtInt(d.totals.calls)} ${rateInfo}`]].map(x=>`<div class="metric"><span>${x[0]}</span><strong>${x[1]}</strong></div>`).join('');$('#usage-line').innerHTML=lineChart(d.series,rate);$('#usage-models').innerHTML=d.byModel.length?'<div class="barlist">'+d.byModel.map((m,idx)=>`<div class="bar-row"><span class="bar-label" title="${esc(m.model)}">${esc(m.model)}</span><div class="bar-track"><div class="bar-fill" style="width:${Math.max(2,m.totalTokens/Math.max(...d.byModel.map(x=>x.totalTokens),1)*100)}%;background:${COLORS[idx%COLORS.length]}"></div></div><span class="bar-val">${fmtTokens(m.totalTokens)}<br><small class="usd-sub" style="font-size:10px">${fmtBrl(m.costBrl)} · ${fmtUsd(m.costUsd)}</small></span></div>`).join('')+'</div>':'<p class="meta">Sem dados.</p>';const featNames={manager:'Gerente',incident:'Análise de incidentes',embedding:'Embeddings (RAG)'};$('#usage-features').innerHTML=barList(d.byFeature.map(f=>({label:featNames[f.feature]||f.feature,tokens:f.totalTokens})),'label','tokens',v=>fmtTokens(v));$('#usage-agents').innerHTML=d.topAgents.length?'<table class="usage-table"><thead><tr><th>Agente</th><th>Execuções</th><th>Sucesso</th><th>Tempo total</th></tr></thead><tbody>'+d.topAgents.map(a=>`<tr><td>${esc(a.agent)}</td><td>${fmtInt(a.runs)}</td><td>${fmtInt(a.succeeded)}</td><td>${fmtInt(a.totalSeconds)}s</td></tr>`).join('')+'</tbody></table>':'<p class="meta">Nenhuma execução de agente no período.'}
// ---------- Relatórios ----------
let reportOptionsCache=null,reportLastData=null,reportLoading=false;
const localDate=d=>{const x=new Date(d.getTime()-d.getTimezoneOffset()*60000);return x.toISOString().slice(0,10)};
function setReportPreset(preset){const now=new Date(),start=new Date(now),end=new Date(now);start.setHours(0,0,0,0);end.setHours(23,59,59,999);if(preset==='week'){const day=(now.getDay()+6)%7;start.setDate(now.getDate()-day)}else if(preset==='month'){start.setDate(1)}else if(preset==='year'){start.setMonth(0,1)}$('#report-start').value=localDate(start);$('#report-end').value=localDate(end);document.querySelectorAll('.report-preset').forEach(b=>b.classList.toggle('active',b.dataset.preset===preset))}
document.querySelectorAll('.report-preset').forEach(b=>b.onclick=()=>setReportPreset(b.dataset.preset));
function renderReportOptions(o){$('#report-technicians').innerHTML=o.technicians.map(t=>`<label class="check-option" data-search="${esc((t.name+' '+t.username).toLowerCase())}"><input type="checkbox" name="report-tech" value="${t.id}"><span>${esc(t.name)}</span><small>${esc(t.username)}</small></label>`).join('')||'<span class="meta">Nenhum técnico ativo.</span>';$('#report-statuses').innerHTML=o.statuses.map(s=>`<label class="check-option"><input type="checkbox" name="report-status" value="${s.id}" checked> ${esc(s.label)}</label>`).join('');$('#report-types').innerHTML=o.types.map(t=>`<label class="check-option"><input type="checkbox" name="report-type" value="${t.id}" checked> ${esc(t.label)}</label>`).join('')}
async function loadReports(){if(!$('#report-start').value)setReportPreset('month');if(reportOptionsCache)return;reportOptionsCache=await api('/reports/options');renderReportOptions(reportOptionsCache)}
$('#report-tech-search').oninput=e=>{const q=e.target.value.toLowerCase().trim();document.querySelectorAll('#report-technicians .check-option').forEach(row=>row.style.display=!q||row.dataset.search.includes(q)?'flex':'none')};
function toggleAllReportTechs(){const boxes=[...document.querySelectorAll('input[name="report-tech"]')].filter(x=>x.closest('.check-option').style.display!=='none'),all=boxes.length&&boxes.every(x=>x.checked);boxes.forEach(x=>x.checked=!all)}
function selectedReportValues(name){return [...document.querySelectorAll(`input[name="${name}"]:checked`)].map(x=>Number(x.value))}
function reportPayload(){return{start:$('#report-start').value+'T00:00:00',end:$('#report-end').value+'T23:59:59.999',dateBasis:$('#report-date-basis').value,technicianIds:selectedReportValues('report-tech'),includeUnassigned:$('#report-unassigned').checked,statuses:selectedReportValues('report-status'),types:selectedReportValues('report-type'),includeDetails:$('#report-details').checked}}
function fmtHours(v){if(v===null||v===undefined)return'—';return v<24?`${Number(v).toFixed(1)}h`:`${(Number(v)/24).toFixed(1)}d`}
function renderReport(d){reportLastData=d;$('#report-empty').classList.add('hidden');$('#report-result').classList.remove('hidden');$('#report-metrics').innerHTML=[['Chamados',d.summary.total],['Ativos',d.summary.active],['Resolvidos',d.summary.resolved],['Taxa de resolução',d.summary.resolutionRate+'%'],['Tempo médio',fmtHours(d.summary.averageResolutionHours)]].map(x=>`<div class="metric"><span>${x[0]}</span><strong>${x[1]}</strong></div>`).join('');$('#report-status-chart').innerHTML=barList(d.byStatus.map(x=>({label:x.label,value:x.count})),'label','value',fmtInt);$('#report-tech-chart').innerHTML=barList(d.byTechnician.slice(0,10).map(x=>({label:x.name,value:x.tickets})),'label','value',fmtInt);$('#report-team-table').innerHTML=d.byTechnician.length?`<table class="report-table"><thead><tr><th>Técnico</th><th>Chamados</th><th>Ativos</th><th>Resolvidos</th><th>Tarefas</th><th>Conclusão tarefas</th></tr></thead><tbody>${d.byTechnician.map(t=>`<tr><td><strong>${esc(t.name)}</strong></td><td>${t.tickets}</td><td>${t.active}</td><td>${t.resolved}</td><td>${t.tasksDone}/${t.tasks}</td><td>${t.tasks?Math.round(t.tasksDone/t.tasks*100):0}%</td></tr>`).join('')}</tbody></table>`:'<p class="meta">Nenhum técnico encontrado para os filtros.</p>';const shown=d.tickets.slice(0,300);$('#report-ticket-caption').textContent=d.tickets.length>300?`Mostrando 300 de ${d.tickets.length}; o PDF inclui todos.`:`${d.tickets.length} chamados no período.`;$('#report-ticket-table').innerHTML=shown.length?`<table class="report-table"><thead><tr><th>Chamado</th><th>Status</th><th>Técnico</th><th>Criado</th><th>Tempo</th><th>Atividades</th></tr></thead><tbody>${shown.map(t=>`<tr><td class="report-ticket-title"><strong>#${t.id} · ${esc(t.title)}</strong><small>${esc(t.typeLabel)}${t.description?' · '+esc(t.description):''}</small></td><td><span class="glpi-status s${t.status}">${esc(t.statusLabel)}</span></td><td>${esc(t.technicians.map(x=>x.name).join(', ')||'Não atribuído')}</td><td>${t.createdAt?new Date(t.createdAt).toLocaleDateString('pt-BR'):'—'}</td><td>${fmtHours(t.resolutionHours??t.ageHours)}</td><td>${t.tasksDone}/${t.tasksTotal} tarefas · ${t.followups} acompanh.</td></tr>`).join('')}</tbody></table>`:'<p class="meta">Nenhum chamado corresponde aos filtros selecionados.</p>'}
$('#report-form').onsubmit=async e=>{e.preventDefault();if(reportLoading)return;reportLoading=true;const form=$('.report-filters');form.classList.add('report-loading');try{renderReport(await api('/reports/preview',{method:'POST',body:JSON.stringify(reportPayload())}))}catch(err){alert(err.message)}finally{reportLoading=false;form.classList.remove('report-loading')}};
async function downloadReportPdf(){if(reportLoading)return;reportLoading=true;const btn=$('#report-pdf'),old=btn.textContent;btn.disabled=true;btn.textContent='Gerando PDF...';try{const r=await fetch('/api/reports/pdf',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(reportPayload())});if(!r.ok){const e=await r.json().catch(()=>({error:r.statusText}));throw new Error(e.error||r.statusText)}const blob=await r.blob(),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=(r.headers.get('content-disposition')?.match(/filename="([^"]+)"/)?.[1])||'relatorio-chamados.pdf';document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(url)}catch(err){alert(err.message)}finally{reportLoading=false;btn.disabled=false;btn.textContent=old}}
function loadPage(p){({dashboard:loadDashboard,manager:loadManager,agents:loadAgents,projetos:loadProjetos,consumo:loadUsage,reports:loadReports,settings:loadSettings,runs:loadRuns,ferramentas:loadFerramentas}[p]||(()=>{}))()}function refresh(){const a=document.querySelector('.page.active');if(!a)return;if(a.id.startsWith('view-')){const f=a.querySelector('iframe');if(f)f.src=f.dataset.src}else loadPage(a.id)}
// ----- Ferramentas (Visual / Pentest / Stress) -----
let currentTool='visual',toolDetailId=null,toolPollTimer=null,toolProjects=[];
const TOOL_META={visual:['Regressão Visual','Playwright · screenshots por tela'],pentest:['Pentest','Headers, CORS, TLS, webhook, rate limit + ZAP'],stress:['Teste de Carga','k6 · p50/p95/p99 e ponto de ruptura']};
const TOOL_STATUS={QUEUED:['Na fila','q'],RUNNING:['Executando','r'],SUCCEEDED:['Concluído','s'],FAILED:['Falhou','f'],CANCELLED:['Cancelado','c'],TIMED_OUT:['Timeout','f']};
function projectOptsHtml(){const none='<option value="">— sem análise de código (só DAST) —</option>';return none+toolProjects.map(p=>`<option value="${esc(p.id)}">${esc(p.name)} (${p.sshAuthType==='pm2'?'local':esc(p.sshHost||'ssh')})</option>`).join('')}
async function loadToolProjects(){try{toolProjects=await api('/tools/projects');const sel=$('#tool-project');if(sel){const current=sel.value;sel.innerHTML=projectOptsHtml();if(current&&[...sel.options].some(o=>o.value===current))sel.value=current;else if(!current&&toolProjects.length===1)sel.value=toolProjects[0].id;await loadSubprojects()}}catch{}}
async function loadSubprojects(){const sel=$('#tool-project'),wrap=$('#tool-subproject-wrap');if(!wrap)return;const pid=sel&&sel.value;if(!pid){wrap.innerHTML='';return}wrap.innerHTML='<span class="meta">Detectando subprojetos…</span>';try{const data=await api('/tools/projects/'+pid+'/subprojects');const subs=(data&&data.subprojects)||[];if(!subs.length){wrap.innerHTML='';return}let opts='';if(data.rootHasManifest)opts+='<option value="">(raiz do projeto)</option>';opts+=subs.map(s=>`<option value="${esc(s.path)}">${esc(s.name)} · ${esc(s.type)}</option>`).join('');if(!data.rootHasManifest)opts+='<option value="">(todas as apps — mais lento)</option>';wrap.innerHTML=`<label>Subprojeto (SAST + SCA)<select id="tool-subproject">${opts}</select></label>`}catch(e){wrap.innerHTML=''}}
function toolOptsHtml(kind){if(kind==='visual')return `<label>Telas<select id="tool-screens"><option value="all">Todas as telas</option>${['login','inbox','crm','financeiro','campanhas','configuracoes','calendario','automacoes'].map(s=>`<option value="${s}">${s}</option>`).join('')}</select></label>`;if(kind==='pentest')return `<label>Projeto (SAST + SCA)<select id="tool-project" onchange="loadSubprojects()">${projectOptsHtml()}</select></label><div id="tool-subproject-wrap"></div><label class="check"><input type="checkbox" id="tool-zap"> Rodar OWASP ZAP (requer Docker)</label><label class="check"><input type="checkbox" id="tool-auth"> Autorizar sondas ativas (brute force)</label>`;return `<label>Cenário<select id="tool-scenario"><option value="baseline">Baseline (10 VU / 2m)</option><option value="pico">Pico (50 VU / 5m)</option><option value="thundering">Thundering herd (100 VU / 30s)</option><option value="sustained">Sustentado (30 VU / 30m)</option><option value="cpu">Limite CPU (80 VU / 5m)</option></select></label>`}
function selectTool(kind){currentTool=kind;document.querySelectorAll('.tools-tab').forEach(b=>b.classList.toggle('active',b.dataset.tool===kind));$('#tools-title').textContent=TOOL_META[kind][0];$('#tools-desc').textContent=TOOL_META[kind][1];$('#tool-opts').innerHTML=toolOptsHtml(kind);if(kind==='pentest')loadToolProjects();toolDetailId=null;$('#tools-detail').innerHTML='<div class="empty-state">Selecione uma execução para ver o passo-a-passo, o relatório e o uso de tokens.</div>';loadToolRuns()}
function loadFerramentas(){if(!$('#tool-opts').innerHTML){$('#tool-opts').innerHTML=toolOptsHtml(currentTool)}if(currentTool==='pentest')loadToolProjects();loadToolRuns()}
async function loadToolRuns(){try{const runs=await api('/tools/runs?kind='+currentTool);$('#tools-runs').innerHTML=runs.length?runs.map(r=>{const st=TOOL_STATUS[r.status]||[r.status,'q'];return `<div class="tool-run ${toolDetailId===r.id?'sel':''}" onclick="openToolRun('${r.id}')"><div class="tool-run-top"><span class="tool-badge b-${st[1]}">${st[0]}</span><span class="tool-run-when">${new Date(r.createdAt).toLocaleString('pt-BR')}</span></div><div class="tool-run-tgt">${esc(r.targetUrl||'—')}</div><div class="tool-run-meta">${r.summary?esc(r.summary).slice(0,90):'…'}</div><div class="tool-run-meta">${(r.totalTokens||0).toLocaleString('pt-BR')} tokens${r.durationMs?' · '+Math.round(r.durationMs/1000)+'s':''}</div></div>`}).join(''):'<p class="meta" style="padding:8px">Nenhuma execução ainda.</p>'}catch(e){$('#tools-runs').innerHTML='<p class="meta">'+esc(e.message)+'</p>'}}
async function runTool(ev){ev.preventDefault();const btn=$('#tool-run-btn'),old=btn.textContent;btn.disabled=true;btn.textContent='Iniciando...';const params={};let projectId;if(currentTool==='visual')params.screens=$('#tool-screens').value;else if(currentTool==='pentest'){params.zap=$('#tool-zap').checked;params.authorized=$('#tool-auth').checked;projectId=$('#tool-project')?.value||undefined;const sp=$('#tool-subproject')?.value;if(sp)params.subPath=sp}else params.scenario=$('#tool-scenario').value;try{const body={targetUrl:$('#tool-url').value.trim()||undefined,projectId,params};const r=await api('/tools/'+currentTool+'/run',{method:'POST',body:JSON.stringify(body)});await loadToolRuns();openToolRun(r.id)}catch(e){alert(e.message)}finally{btn.disabled=false;btn.textContent=old}return false}
async function openToolRun(id){toolDetailId=id;document.querySelectorAll('.tool-run').forEach(el=>el.classList.toggle('sel',el.getAttribute('onclick').includes(id)));try{const run=await api('/tools/runs/'+id);renderToolDetail(run);if(toolPollTimer)clearInterval(toolPollTimer);if(run.status==='RUNNING'||run.status==='QUEUED')toolPollTimer=setInterval(()=>refreshToolDetail(id),2000)}catch(e){$('#tools-detail').innerHTML='<p class="meta">'+esc(e.message)+'</p>'}}
async function refreshToolDetail(id){if(toolDetailId!==id||!$('#ferramentas').classList.contains('active')){clearInterval(toolPollTimer);return}try{const run=await api('/tools/runs/'+id);renderToolDetail(run);if(run.status!=='RUNNING'&&run.status!=='QUEUED'){clearInterval(toolPollTimer);loadToolRuns()}}catch(e){}}
function renderToolDetail(run){const st=TOOL_STATUS[run.status]||[run.status,'q'];const steps=Array.isArray(run.steps)?run.steps:[];const running=run.status==='RUNNING'||run.status==='QUEUED';const timeline=steps.map(s=>`<div class="tl-step st-${s.status}"><span class="tl-dot"></span><div class="tl-body"><div class="tl-label">${esc(s.label)}<span class="tl-time">${new Date(s.ts).toLocaleTimeString('pt-BR')}</span></div>${s.detail?`<div class="tl-detail">${esc(s.detail)}</div>`:''}</div></div>`).join('')||'<p class="meta">Sem passos ainda…</p>';let findingsHtml='';if(run.findings&&Array.isArray(run.findings)){findingsHtml=`<div class="tool-findings">${run.findings.map(f=>`<div class="finding sev-${esc(f.severidade||'info')}"><div class="finding-top"><span class="sev-tag">${esc((f.severidade||'info').toUpperCase())}</span><strong>${esc(f.categoria||'')}</strong></div><div>${esc(f.descricao||'')}</div>${f.evidencia?`<div class="finding-ev">${esc(f.evidencia)}</div>`:''}${f.correcao?`<div class="finding-fix">↳ ${esc(f.correcao)}</div>`:''}</div>`).join('')}</div>`}
$('#tools-detail').innerHTML=`<div class="detail-head"><div><span class="tool-badge b-${st[1]}">${st[0]}</span> <strong>${esc(run.targetUrl||'—')}</strong></div><div class="detail-actions">${running?`<button class="ghost" onclick="cancelToolRun('${run.id}')">Cancelar</button>`:''}<a class="ghost btn-link" href="/api/tools/runs/${run.id}/report.pdf" target="_blank">Baixar PDF ↗</a></div></div>
<div class="detail-kpis"><div class="metric"><span>Tokens</span><strong>${(run.totalTokens||0).toLocaleString('pt-BR')}</strong></div><div class="metric"><span>Duração</span><strong>${run.durationMs?Math.round(run.durationMs/1000)+'s':'—'}</strong></div><div class="metric"><span>Entrada/Saída</span><strong>${run.promptTokens||0}/${run.outputTokens||0}</strong></div></div>
${run.summary?`<div class="detail-summary">${esc(run.summary)}</div>`:''}
<h3 class="detail-h">Passo a passo</h3><div class="timeline">${timeline}</div>
${findingsHtml?`<h3 class="detail-h">Achados</h3>${findingsHtml}`:''}
${run.report?`<h3 class="detail-h">Relatório</h3><div class="md-body">${mdToHtml(run.report)}</div>`:''}
${run.generatedScript?`<details class="tool-script"><summary>Script gerado</summary><pre class="md-code"><code>${esc(run.generatedScript)}</code></pre></details>`:''}`}
async function cancelToolRun(id){try{await api('/tools/runs/'+id+'/cancel',{method:'POST',body:'{}'});openToolRun(id);loadToolRuns()}catch(e){alert(e.message)}}
loadViews().finally(routeFromPath);
